   340→
   341→  setViewpoint(viewpoint) {
   342→    let umat;
   343→    let hemisphere = 'left'; // Default to left hemisphere
   344→
   345→    // Check if there are any surfaces and if the first one has a hemisphere property
   346→    const firstSurface = this.surfaces.values().next().value;
   347→    if (firstSurface && firstSurface.hemisphere) {
   348→      hemisphere = firstSurface.hemisphere;
   349→    }
   350→
   351→    const fullViewpoint = `${hemisphere}_${viewpoint}`;
   352→
   353→    if (this.viewpoints[fullViewpoint]) {
   354→      umat = this.viewpoints[fullViewpoint];
   355→    } else {
   356→      console.warn(`Unknown viewpoint: ${fullViewpoint}`);
   357→      umat = new THREE.Matrix4().identity();
   358→    }
   359→
   360→    debugLog('Setting viewpoint to:', viewpoint);
   361→    debugLog('Current viewpoint state:', this.viewpointState);
   362→    debugLog('umat', umat);
   363→
   364→    // Calculate the bounding box of all surfaces
   365→    const box = new THREE.Box3();
   366→    this.surfaces.forEach(surface => {
   367→      box.expandByObject(surface.mesh);
   368→    });
   369→    const center = box.getCenter(new THREE.Vector3());
   370→    const size = box.getSize(new THREE.Vector3());
   371→    const maxDim = Math.max(size.x, size.y, size.z);
   372→
   373→    // Set camera position based on umat
   374→    const distance = maxDim * this.config.initialZoom; // Adjust this multiplier as needed
   375→    const cameraPosition = new THREE.Vector3(0, 0, distance).applyMatrix4(umat);
   376→    this.camera.position.copy(cameraPosition.add(center));
   377→
   378→    // Set camera up vector
   379→    const up = new THREE.Vector3(0, 1, 0).applyMatrix4(umat);
   380→    this.camera.up.copy(up);
   381→
   382→    // Set camera look at
   383→    this.camera.lookAt(center);
   384→
   385→    // Update controls
   386→    this.controls.target.copy(center);
   387→    this.controls.update();
   388→
   389→    this.viewpoint = viewpoint;
   390→    if (this.viewpointState) {
   391→      this.viewpointState.viewpoint = viewpoint;
   392→    }
   393→   
   394→    this.render();
   395→  }
   396→
   397→  updateColormap(presetName) {
   398→    this.surfaces.forEach(surface => {
   399→      if (surface instanceof ColorMappedNeuroSurface) {
   400→        surface.setColorMap(ColorMap.fromPreset(presetName));
   401→        surface.updateColors();
   402→      }
   403→    });
   404→    this.render();
   405→  }
   406→
   407→  updateAmbientLight(color) {
   408→    if (this.ambientLight) {
   409→      this.ambientLight.color.setHex(color);
   410→      this.render();
   411→    }
   412→  }
   413→
   414→  updateDirectionalLight(color) {
   415→    if (this.directionalLight) {
   416→      this.directionalLight.color.setHex(color);
   417→      this.render();
   418→    }
   419→  }
   420→
   421→  updateDirectionalLightIntensity(intensity) {
   422→    if (this.directionalLight) {
   423→      this.directionalLight.intensity = intensity;
   424→      this.render();
   425→    }
   426→  }
   427→
   428→  updateMaterials() {
   429→    this.surfaces.forEach(surface => {
   430→      if (!surface.mesh) return;
   431→      if (!surface.mesh.material || !surface.mesh.material.isMeshPhysicalMaterial) {
   432→        surface.mesh.material = new THREE.MeshPhysicalMaterial({
   433→          metalness: this.config.metalness,
   434→          roughness: this.config.roughness,
   435→          clearcoat: 0.2,
   436→          reflectivity: 0.45,
   437→          vertexColors: true,
   438→          envMapIntensity: 0.8,
   439→          dithering: true,
   440→          side: THREE.DoubleSide
   441→        });
   442→      }
   443→      surface.mesh.material.metalness = this.config.metalness;
   444→      surface.mesh.material.roughness = this.config.roughness;
   445→      surface.mesh.geometry.computeVertexNormals();
   446→      surface.mesh.material.needsUpdate = true;
   447→    });
   448→    this.render();
   449→  }
   450→
   451→  updateIntensityRange() {
   452→    debugLog('NeuroSurfaceViewer: Updating intensity range', [this.intensityRange.range.min, this.intensityRange.range.max]);
   453→    this.surfaces.forEach(surface => {
   454→      if (surface instanceof ColorMappedNeuroSurface) {
   455→        surface.colorMap.setRange([this.intensityRange.range.min, this.intensityRange.range.max]);
   456→      }
   457→    });
   458→    // The surface should update automatically due to the event listener
   459→  }
   460→
   461→  updateThresholdRange() {
   462→    debugLog('NeuroSurfaceViewer: Updating threshold range', [this.thresholdRange.range.min, this.thresholdRange.range.max]);
   463→    this.surfaces.forEach(surface => {
   464→      if (surface instanceof ColorMappedNeuroSurface) {
   465→        surface.colorMap.setThreshold([this.thresholdRange.range.min, this.thresholdRange.range.max]);
   466→      }
   467→    });
   468→    // The surface should update automatically due to the event listener
   469→  }
   470→
   471→  resetCamera() {
   472→    if (this.camera && this.controls) {
   473→      this.setViewpoint(this.viewpoint); // Reset to the current viewpoint
   474→      this.render();
   475→    }
   476→  }
   477→
   478→  addSurface(surface, id) {
   479→    debugLog('Adding surface:', surface, 'with id:', id);
   480→    this.surfaces.set(id, surface);
   481→    if (!surface.mesh) {
   482→      console.warn('Surface mesh not created. Creating now.');
   483→      surface.createMesh();
   484→    }
   485→    if (surface.mesh && surface.mesh.material) {
   486→      this.applyRimLighting(surface.mesh.material);
   487→      this.applyCurvatureShading(surface.mesh);
   488→    }
   489→    this.scene.add(surface.mesh);
   490→    this.updateMaterials();
   491→    
   492→    // Update data range for any surface with data
   493→    if (surface.data && surface.data.length > 0) {
   494→      debugLog('Updating data range for surface with data');
   495→      this.updateDataRange(surface.data);
   496→      this.updateRangeControls();
   497→    } else {
   498→      debugLog('Surface has no data, using default ranges');
   499→      // For surfaces without data (like basic SurfaceGeometry), set reasonable defaults
   500→      this.updateDataRange([0, 1]);
   501→      this.updateRangeControls();
   502→    }
   503→    
   504→    if (this.surfaces.size === 1) {
   505→      this.resetCamera(); // Center the camera when the first surface is added
   506→    }
   507→    this.render();
   508→  }
   509→
   510→  updateDataRange(data) {
   511→    if (!data || data.length === 0) {
   512→      debugLog('No data provided to updateDataRange, using defaults');
   513→      this.dataRange.min = 0;
   514→      this.dataRange.max = 1;
   515→      this.intensityRange.range.min = 0;
   516→      this.intensityRange.range.max = 1;
   517→      this.thresholdRange.range.min = 0;
   518→      this.thresholdRange.range.max = 0;
   519→      return;
   520→    }
   521→
   522→    const validData = data.filter(d => d !== null && d !== undefined && !isNaN(d));
   523→    if (validData.length === 0) {
   524→      debugLog('No valid data found, using defaults');
   525→      this.dataRange.min = 0;
   526→      this.dataRange.max = 1;
   527→      this.intensityRange.range.min = 0;
   528→      this.intensityRange.range.max = 1;
   529→      this.thresholdRange.range.min = 0;
   530→      this.thresholdRange.range.max = 0;
   531→      return;
   532→    }
   533→
   534→    const min = Math.min(...validData);
   535→    const max = Math.max(...validData);
   536→    
   537→    debugLog('Data range detected:', { min, max, dataPoints: validData.length });
   538→    
   539→    this.dataRange.min = min;
   540→    this.dataRange.max = max;
   541→
   542→    // Update intensity range to match data range
   543→    this.intensityRange.range.min = min;
   544→    this.intensityRange.range.max = max;
   545→
   546→    // Set threshold range to a reasonable default (middle 50% of data)
   547→    const range = max - min;
   548→    const quarterRange = range * 0.25;
   549→    this.thresholdRange.range.min = min + quarterRange;
   550→    this.thresholdRange.range.max = max - quarterRange;
   551→
   552→    debugLog('Updated ranges:', {
   553→      dataRange: this.dataRange,
   554→      intensityRange: this.intensityRange.range,
