   576→      this.intensityRange.range.min = Math.max(this.intensityRange.range.min, this.dataRange.min);
   577→      this.intensityRange.range.max = Math.min(this.intensityRange.range.max, this.dataRange.max);
   578→      
   579→      this.thresholdRange.range.min = Math.max(this.thresholdRange.range.min, this.dataRange.min);
   580→      this.thresholdRange.range.max = Math.min(this.thresholdRange.range.max, this.dataRange.max);
   581→      
