   726→        shader.uniforms.coolColor = { value: new THREE.Color(0x3366ff) };
   727→        shader.vertexShader = shader.vertexShader.replace(
   728→          'void main()',
   729→          'attribute float curv;\nvarying float vCurv;\nvoid main()'
   730→        );
   731→        shader.vertexShader = shader.vertexShader.replace(
   732→          '#include <begin_vertex>',
   733→          '#include <begin_vertex>\nvCurv = curv;'
   734→        );
   735→        shader.fragmentShader = shader.fragmentShader.replace(
   736→          'void main() {',
   737→          'varying float vCurv;\nuniform vec3 warmColor;\nuniform vec3 coolColor;\nvoid main() {'
   738→        );
   739→        shader.fragmentShader = shader.fragmentShader.replace(
   740→          '#include <dithering_fragment>',
   741→          '#include <dithering_fragment>\nfloat c = smoothstep(-0.5,0.5,vCurv);\nvec3 tint = mix(coolColor,warmColor,c);\n gl_FragColor.rgb = mix(gl_FragColor.rgb, tint, 0.4);'
   742→        );
   743→      };
   744→      mesh.material.needsUpdate = true;
   745→    } else {
   746→      const colors = mesh.geometry.getAttribute('color');
   747→      if (!colors) return;
   748→      const arr = colors.array;
   749→      const curv = curvAttr.array;
   750→      for (let i = 0; i < curv.length; i++) {
   751→        const t = curv[i] > 0 ? [1, 0.7, 0.7] : [0.7, 0.7, 1];
   752→        const idx = i * 3;
   753→        arr[idx] *= t[0];
   754→        arr[idx + 1] *= t[1];
   755→        arr[idx + 2] *= t[2];
   756→      }
   757→      colors.needsUpdate = true;
   758→    }
