dispose() {
  // Stop animation loop
  this.stop();

  // Dispose all surfaces
  this.surfaces.forEach((surface, id) => {
    this.removeSurface(id);
  });
  this.surfaces.clear();

  // Remove event listeners
  if (this.controls) {
    this.controls.removeEventListener('change', this.onControlsChange);
    this.controls.dispose();
    this.controls = null;
  }

  // Dispose of scene objects
  this.scene.traverse((object) => {
    if (object.geometry) {
      object.geometry.dispose();
    }
    if (object.material) {
      if (Array.isArray(object.material)) {
        object.material.forEach(material => {
          this.disposeMaterial(material);
        });
      } else {
        this.disposeMaterial(object.material);
      }
    }
  });

  // Clear scene
  while(this.scene.children.length > 0) {
    this.scene.remove(this.scene.children[0]);
  }

  // Dispose post-processing
  if (this.composer) {
    // Dispose render targets
    if (this.composer.renderTarget1) {
      this.composer.renderTarget1.dispose();
    }
    if (this.composer.renderTarget2) {
      this.composer.renderTarget2.dispose();
    }
    this.composer = null;
    this.renderPass = null;
    this.ssaoPass = null;
  }

  // Dispose renderer
  if (this.renderer) {
    this.renderer.dispose();
    this.renderer.forceContextLoss();
    this.renderer.domElement = null;
    this.renderer = null;
  }

  // Dispose Tweakpane
  if (this.pane && typeof this.pane.dispose === 'function') {
    this.pane.dispose();
  }
  if (this.paneContainer && this.paneContainer.parentNode) {
    this.paneContainer.parentNode.removeChild(this.paneContainer);
    this.paneContainer = null;
  }

  // Clear references
  this.camera = null;
  this.scene = null;
  this.ambientLight = null;
  this.directionalLight = null;
  this.light = null;
  this.environmentMap = null;
}

disposeMaterial(material) {
  if (material.map) material.map.dispose();
  if (material.lightMap) material.lightMap.dispose();
  if (material.bumpMap) material.bumpMap.dispose();
  if (material.normalMap) material.normalMap.dispose();
  if (material.specularMap) material.specularMap.dispose();
  if (material.envMap) material.envMap.dispose();
  material.dispose();
}

