          colors[colorIndex + 1] = overlayAlpha * color[1] + (1 - overlayAlpha) * baseSurfaceColor.g;
          colors[colorIndex + 2] = overlayAlpha * color[2] + (1 - overlayAlpha) * baseSurfaceColor.b;
          colors[colorIndex + 3] = 1; // Always opaque
        }
      }
